<template>
  <div class="page-bg"><section class="page-banner compact"><div class="container"><span class="eyebrow">为它寻找新家</span><h1>{{ editing ? '编辑宠物信息' : '发布寄养信息' }}</h1><p>信息越完整，越容易遇见真正合适的领养人。</p></div></section><div class="container publish-wrap"><el-steps :active="activeStep" simple finish-status="success"><el-step title="选择分类" icon="el-icon-menu" /><el-step title="填写资料" icon="el-icon-edit" /><el-step title="上传照片" icon="el-icon-picture-outline" /></el-steps><el-form ref="form" :model="form" :rules="rules" label-position="top" class="publish-form"><section class="form-section"><div class="form-section-title"><span>01</span><div><h2>宠物分类</h2><p>先告诉大家它是哪一类小伙伴</p></div></div><el-row :gutter="24"><el-col :span="12"><el-form-item label="宠物大类" prop="categoryId"><el-select v-model="form.categoryId" placeholder="请选择大类" @change="categoryChanged"><el-option v-for="item in categories" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item></el-col><el-col :span="12"><el-form-item label="细分品种" prop="subcategoryId"><el-select v-model="form.subcategoryId" placeholder="请选择细分类" @change="subcategoryChanged"><el-option v-for="item in subcategories" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item></el-col></el-row></section><section class="form-section"><div class="form-section-title"><span>02</span><div><h2>基础资料</h2><p>让领养人快速认识它</p></div></div><el-row :gutter="24"><el-col :span="24"><el-form-item label="宠物名称" prop="name"><el-input v-model.trim="form.name" maxlength="40" placeholder="例如：糯米" /></el-form-item></el-col><el-col :span="8"><el-form-item label="年龄（月）" prop="ageMonths"><el-input-number v-model="form.ageMonths" :min="0" :max="600" controls-position="right" /></el-form-item></el-col><el-col :span="8"><el-form-item label="性别" prop="gender"><el-radio-group v-model="form.gender"><el-radio-button label="MALE">弟弟</el-radio-button><el-radio-button label="FEMALE">妹妹</el-radio-button><el-radio-button label="UNKNOWN">未知</el-radio-button></el-radio-group></el-form-item></el-col><el-col :span="8"><el-form-item label="体重（kg）"><el-input-number v-model="form.weight" :min="0" :max="200" :precision="2" controls-position="right" /></el-form-item></el-col><el-col :span="24"><el-form-item label="性格特点"><el-input v-model.trim="form.personality" maxlength="255" placeholder="例如：温柔亲人、活泼好动、慢热安静" /></el-form-item></el-col></el-row></section><section class="form-section"><div class="form-section-title"><span>03</span><div><h2>健康与照护</h2><p>真实透明的信息是负责的第一步</p></div></div><el-row :gutter="24"><el-col :span="8"><el-form-item label="疫苗情况"><el-select v-model="form.vaccineStatus" allow-create filterable><el-option label="疫苗齐全" value="疫苗齐全" /><el-option label="完成基础疫苗" value="完成基础疫苗" /><el-option label="未接种" value="未接种" /></el-select></el-form-item></el-col><el-col :span="8"><el-form-item label="驱虫情况"><el-select v-model="form.dewormStatus" allow-create filterable><el-option label="已定期驱虫" value="已定期驱虫" /><el-option label="未驱虫" value="未驱虫" /></el-select></el-form-item></el-col><el-col :span="8"><el-form-item label="绝育情况"><el-select v-model="form.sterilizationStatus" allow-create filterable><el-option label="已绝育" value="已绝育" /><el-option label="未绝育" value="未绝育" /></el-select></el-form-item></el-col><el-col :span="24"><el-form-item label="健康情况" prop="healthStatus"><el-input v-model.trim="form.healthStatus" type="textarea" :rows="2" maxlength="255" show-word-limit /></el-form-item></el-col><el-col :span="24"><el-form-item label="饲养注意事项" prop="feedingNotes"><el-input v-model.trim="form.feedingNotes" type="textarea" :rows="3" maxlength="1000" show-word-limit /></el-form-item></el-col><el-col :span="24"><el-form-item label="主人寄语"><el-input v-model.trim="form.ownerMessage" type="textarea" :rows="3" maxlength="1000" show-word-limit /></el-form-item></el-col></el-row></section><section class="form-section"><div class="form-section-title"><span>04</span><div><h2>宠物照片</h2><p>支持多图，第一张将自动设为封面</p></div></div><el-form-item prop="images"><el-upload action="/api/upload" list-type="picture-card" :headers="uploadHeaders" :file-list="fileList" :on-success="uploadSuccess" :on-remove="removeImage" :on-preview="previewImage" :before-upload="beforeUpload" :limit="8" multiple><i class="el-icon-plus" /><div slot="tip" class="el-upload__tip">最多 8 张，单张不超过 10MB，建议使用正方形清晰照片</div></el-upload></el-form-item></section><div class="publish-actions"><el-button size="large" @click="$router.back()">取消</el-button><el-button type="primary" size="large" :loading="submitting" @click="submit">{{ editing ? '保存修改' : '确认发布' }}</el-button></div></el-form></div><el-dialog :visible.sync="previewVisible" width="600px"><img class="upload-preview" :src="previewUrl"></el-dialog></div>
</template>
<script>
import {categoryApi,petApi} from '../api'
const emptyForm=()=>({categoryId:null,subcategoryId:null,name:'',breed:'',ageMonths:1,gender:'MALE',weight:1,personality:'',vaccineStatus:'疫苗齐全',dewormStatus:'已定期驱虫',sterilizationStatus:'已绝育',healthStatus:'',feedingNotes:'',ownerMessage:'',images:[]})
export default { data:()=>({categories:[],form:emptyForm(),fileList:[],previewVisible:false,previewUrl:'',submitting:false,rules:{categoryId:[{required:true,message:'请选择宠物大类',trigger:'change'}],subcategoryId:[{required:true,message:'请选择细分类',trigger:'change'}],name:[{required:true,message:'请输入宠物名称',trigger:'blur'}],ageMonths:[{required:true,message:'请输入年龄',trigger:'change'}],gender:[{required:true,message:'请选择性别',trigger:'change'}],healthStatus:[{required:true,message:'请填写健康情况',trigger:'blur'}],feedingNotes:[{required:true,message:'请填写饲养注意事项',trigger:'blur'}],images:[{type:'array',required:true,min:1,message:'请至少上传一张照片',trigger:'change'}]}}), computed:{editing(){return Boolean(this.$route.params.id)},subcategories(){const c=this.categories.find(x=>x.id===this.form.categoryId);return c?c.children:[]},uploadHeaders(){return{Authorization:`Bearer ${localStorage.getItem('pet_token')}`}},activeStep(){if(this.form.images.length)return 3;if(this.form.name)return 2;if(this.form.categoryId)return 1;return 0}}, async created(){this.categories=await categoryApi.tree();if(this.editing){const pet=await petApi.detail(this.$route.params.id);Object.keys(this.form).forEach(k=>{if(pet[k]!==undefined)this.form[k]=pet[k]});this.fileList=pet.images.map((url,i)=>({name:`宠物照片${i+1}`,url}))}}, methods:{categoryChanged(){this.form.subcategoryId=null;this.form.breed=''},subcategoryChanged(id){const selected=this.subcategories.find(item=>item.id===id);this.form.breed=selected?selected.name:''},beforeUpload(file){const ok=/^image\/(jpeg|png|webp|gif)$/.test(file.type)&&file.size/1024/1024<10;if(!ok)this.$message.error('请选择 10MB 以内的 jpg、png、webp 或 gif 图片');return ok},uploadSuccess(res,file){if(res.code!==200){this.$message.error(res.message);return}file.url=res.data.url;this.form.images.push(res.data.url);this.$refs.form.validateField('images')},removeImage(file){this.form.images=this.form.images.filter(x=>x!==file.url)},previewImage(file){this.previewUrl=file.url;this.previewVisible=true},submit(){this.subcategoryChanged(this.form.subcategoryId);this.$refs.form.validate(async valid=>{if(!valid){this.$message.warning('请检查并补全表单');return}this.submitting=true;try{if(this.editing)await petApi.update(this.$route.params.id,this.form);else await petApi.create(this.form);this.$message.success(this.editing?'修改已保存':'发布成功，宠物已进入分类列表');this.$router.push('/profile?tab=published')}finally{this.submitting=false}})}} }
</script>
